<?php declare(strict_types=1);
namespace SkyFi\System\Repositories;
use SkyFi\System\Contracts\DepartmentRepositoryContract;
final class PdoDepartmentRepository extends PdoSystemRepository implements DepartmentRepositoryContract { private array $allowed=['branch_id','code','name','description','head_user_id','status']; public function list(array $q): array { return $this->listRows('departments',$q,['code','name'],['status','branch_id']); } public function find(int $id): array { return $this->findOne('departments',$id); } public function create(array $d,?int $u=null): array { return $this->insertRow('departments',$this->clean($d),$u); } public function update(int $id,array $d,?int $u=null): array { return $this->updateRow('departments',$id,$this->clean($d),$u); } public function delete(int $id): void { $this->softDeleteRow('departments',$id); } public function status(int $id,string $s,?int $u=null): array { return $this->statusRow('departments',$id,$s,$u); } private function clean(array $d): array { return array_intersect_key($d,array_flip($this->allowed)); }}
